import{_ as s,c as e,a2 as t,o as l}from"./chunks/framework.KtPg9R_8.js";const p="data:image/jpeg;base64,",i="data:image/jpeg;base64,",o="/block-server-wiki/assets/hmcl_version_select.Csma2skP.jpg",c="/block-server-wiki/assets/hmcl_version_select_2.C2a7OUso.jpg",n="/block-server-wiki/assets/hmcl_launch_game.EaFbZ_M4.jpg",d="/block-server-wiki/assets/skinlib_auth.CThwh0pD.jpg",r="/block-server-wiki/assets/skinlib_auth_2.BaxLHmr6.jpg",h="/block-server-wiki/assets/skinlib_user.Bkhug_nF.jpg",x=JSON.parse('{"title":"教 你 怎 么 玩 服 务 器","description":"","frontmatter":{},"headers":[],"relativePath":"zh/index.md","filePath":"zh/index.md","lastUpdated":1739072957000}'),b={name:"zh/index.md"};function u(m,a,g,k,v,A){return l(),e("div",null,a[0]||(a[0]=[t('<h1 id="教-你-怎-么-玩-服-务-器" tabindex="-1">教 你 怎 么 玩 服 务 器 <a class="header-anchor" href="#教-你-怎-么-玩-服-务-器" aria-label="Permalink to &quot;教 你 怎 么 玩 服 务 器&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果您还没有购买Minecraft正版，请考虑立刻购买正版哦~</p><p><a href="https://www.minecraft.net/zh-hans/get-minecraft" target="_blank" rel="noreferrer">购买Minecraft正版</a>（部分地区可能无法正常访问）</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果本文档无法解决您的问题（或是未出现的问题），请联系管理，管理可以手把手教您</p></div><h2 id="安装我的世界" tabindex="-1">安装我的世界 <a class="header-anchor" href="#安装我的世界" aria-label="Permalink to &quot;安装我的世界&quot;">​</a></h2><p>在此之前，我们假定您的电脑是基于NT Core的Windows <s>（毕竟会用linux和mac的基本不会看教程）</s></p><p>如果您没有安装我的世界（Minecraft），或您的设备特殊（如手机），请前往<a href="./install-minecraft/">我的世界简易安装教程</a></p><p>如果您已安装，但不确定您的版本是否可用，请前往<a href="#确定你的我的世界版本">确定你的我的世界版本</a></p><h2 id="确定你的我的世界版本" tabindex="-1">确定你的我的世界版本 <a class="header-anchor" href="#确定你的我的世界版本" aria-label="Permalink to &quot;确定你的我的世界版本&quot;">​</a></h2><h3 id="看启动器" tabindex="-1">看启动器 <a class="header-anchor" href="#看启动器" aria-label="Permalink to &quot;看启动器&quot;">​</a></h3><p>打开您的启动器（如HMCL, PCL2），跟随教程进行操作：</p><details class="details custom-block"><summary>启动器看起来是什么样子的？</summary><p>请记住它们的图标：</p><p>这是PCL2的图标： <img src="'+p+'" alt="PCL2的图标"></p><p>而这是HMCL的图标，它看起来像一个工作台： <img src="'+i+'" alt="HMCL的图标"></p></details><ol><li>双击您的启动器图标，打开您的启动器</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>大部分启动器大同小异，这里以HMCL举例</p></div><ol start="2"><li>找到您启动器的<strong>版本管理</strong>，可以参考如下截图</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果<strong>绿色框内</strong>（也就是<strong>当前版本</strong>）已为合适版本时，您可直接跳过这一步</p></div><p><img src="'+o+'" alt="HMCL启动器版本管理的位置"></p><p>打开版本选择页面后，请选择合适的版本（这里以<strong>原版1.19.4</strong>为例）</p><p><img src="'+c+'" alt="选择合适的版本"></p><p>选择完毕后，点击左上角的<code>←</code>箭头返回到主界面</p><ol start="3"><li>最后就可以点击右下角的启动按钮来启动游戏了</li></ol><p><img src="'+n+'" alt="启动游戏"></p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>不同启动器有不同的布局（如PCL2启动器启动按钮在左下角），若您的启动器为其他启动器，请参考启动器相关文档获取帮助</p></div><details class="details custom-block"><summary>我仍然不会...</summary><p>请善用<a href="javascript:seeerbaidu(&#39;我的世界%20启动器怎么用&#39;)">搜索引擎</a></p></details><details class="details custom-block"><summary>启动器在哪里下载？</summary><p>快点击下方链接 <s>（大雾）</s></p><p><a href="http://mirrors.cloud.tencent.com/nexus/repository/maven-public/org/glavo/hmcl/hmcl-dev/3.5.7.246/hmcl-dev-3.5.7.246.exe" target="_blank" rel="noreferrer">HMCL下载（Windows版）</a></p><p><a href="https://ltcat.lanzoum.com/b0aj6gsid" target="_blank" rel="noreferrer">PCL2下载</a> 提取码：<code>pcl2</code></p><p>*Tip: PCL2需要解压后双击运行，我们<strong>一般</strong>不推荐直接在压缩包内打开运行哦~</p></details><details class="details custom-block"><summary>不会解压缩？</summary><p>请善用<a href="javascript:seeerbaidu(&#39;电脑解压缩教程&#39;)">搜索引擎</a></p></details><h2 id="注册皮肤站" tabindex="-1">注册皮肤站 <a class="header-anchor" href="#注册皮肤站" aria-label="Permalink to &quot;注册皮肤站&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>当前内容不适用，请直接跳转到<a href="#进服地址">进服地址</a>继续</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>为注册皮肤站，您需要拥有一个电子邮箱</p><p>若您没有，你可以查看教程或<a href="./contact/">联系管理员</a></p><p><a href="./email-registration/">邮箱注册教程</a></p></div><p>请点击导航栏中的<a href="https://skin.bytemetasg.top/" target="_blank" rel="noreferrer">皮肤站</a>按钮，该操作会自动跳转至皮肤站（如图）</p><p><img src="'+d+'" alt="皮肤站主页截图"></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>为了方便观察，我们降低了示例中背景图片的亮度</p></div><p>点击下方的<a href="https://skin.bytemetasg.top/auth/register" target="_blank" rel="noreferrer">现在注册</a>按钮，将会跳转到注册界面，在该界面填写您的信息即可（如图）</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>您或许还可以选择<a href="https://skin.bytemetasg.top/auth/login/live" target="_blank" rel="noreferrer">Microsoft Live</a>登录哦~</p></div><p><img src="'+r+'" alt="皮肤站注册界面截图"></p><p><a href="./skinlib_auth_2.jpg">查看大图？</a></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>完成注册后您可能需要打开您的邮件客户端或前往登录对应邮件服务商的网页版</p><p>邮件内有一封激活链接，点击打开即可完成注册</p></div><details class="details custom-block"><summary>我没有收到邮件？</summary><p>你可以检查一下电子邮件的垃圾箱或者稍等一下再试哦~</p></details><details class="details custom-block"><summary>我还是没有收到邮件？？？</summary><p>请与<a href="./contact/">管理员联系</a>，我们会帮您处理</p></details><p>注册完成后，您会自动跳转到注册用户的首页（如图）</p><p><img src="'+h+`" alt="注册用户的首页"></p><p>您接下来只要关注<code>快速配置启动器</code>一栏即可</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>直接跳转至<a href="https://blessing.netlify.app/yggdrasil-api/authlib-injector.html#%E9%85%8D%E7%BD%AE%E5%90%AF%E5%8A%A8%E5%99%A8" target="_blank" rel="noreferrer">启动器配置教程</a>？</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>您可以每天通过点击<code>签到</code>按钮来获取皮肤站内的积分哦~</p></div><h2 id="进服地址" tabindex="-1">进服地址 <a class="header-anchor" href="#进服地址" aria-label="Permalink to &quot;进服地址&quot;">​</a></h2><ul><li>aismc.bid</li><li>ais.yang-qwq.top</li><li>mc.greenspray.cn</li></ul><details class="details custom-block"><summary>我不会添加多人服务器...</summary><p>请善用<a href="javascript:seeerbaidu(&#39;我的世界%20添加多人服务器&#39;)">搜索引擎</a></p></details><h2 id="注册-登录账号" tabindex="-1">注册/登录账号 <a class="header-anchor" href="#注册-登录账号" aria-label="Permalink to &quot;注册/登录账号&quot;">​</a></h2><p>如果你是第一次来服务器，那么在进入之后，请务必执行如下的指令注册账号后，方可开始游玩：</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>请将<code>&lt;密码&gt;</code>、<code>&lt;重复密码&gt;</code>替换为你自己的密码</p><p>如：<code>/reg mypassword mypassword</code></p></div><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/reg &lt;密码&gt; &lt;重复密码&gt;</span></span></code></pre></div><p>如果你已经完成了注册，请在接下来的每次进入服务器后输入登录命令：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/l &lt;密码&gt;</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果你确实是第一次来到服务器，但聊天框内提示请使用<code>/l</code>登录，那么则意味着这个游戏ID已经被人占用了</p><p>请你更换一个游戏后再试</p></div><h2 id="进服第一步" tabindex="-1">进服第一步 <a class="header-anchor" href="#进服第一步" aria-label="Permalink to &quot;进服第一步&quot;">​</a></h2><p>该栏目下的命令均为必要或常用命令，在游玩时记牢可获得最佳体验~</p><h3 id="获取工具" tabindex="-1">获取工具 <a class="header-anchor" href="#获取工具" aria-label="Permalink to &quot;获取工具&quot;">​</a></h3><p>在默认情况下，新手套装在第一次进入时会默认发放</p><details class="details custom-block"><summary>如果没有新手套装...</summary><p>如果出于插件bug无法获取新手套装，请执行<code>/kit newbie</code>获取新手套装(包含附魔皮革套，工具一套，食物，及其他生存用品)</p></details><h3 id="传送" tabindex="-1">传送 <a class="header-anchor" href="#传送" aria-label="Permalink to &quot;传送&quot;">​</a></h3><p>传送到某个玩家：<code>/tpa &lt;玩家ID&gt;</code></p><p>接受玩家的传送：<code>/tpaccept</code></p><p>拒绝玩家的传送：<code>/tpadeny</code></p><p>让玩家传送到你：<code>/tpahere &lt;玩家ID&gt;</code></p><p>随机传送：<code>/tpr</code></p><p>传送到传送点：<code>/warp &lt;传送点名字&gt;</code></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>你知道吗：可以使用<code>/warps</code>获取所有可以使用的传送点哦~</p></div><h3 id="家" tabindex="-1">家 <a class="header-anchor" href="#家" aria-label="Permalink to &quot;家&quot;">​</a></h3><p>设置家：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sethome [家的名字]</span></span></code></pre></div><p>回去：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/home [家的名字]</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>/home bed</code>是传送到床旁边，除非你没床</p></div><h3 id="菜单" tabindex="-1">菜单 <a class="header-anchor" href="#菜单" aria-label="Permalink to &quot;菜单&quot;">​</a></h3><p>点击钟或者输入指令 <code>/cd</code></p><h3 id="私聊" tabindex="-1">私聊 <a class="header-anchor" href="#私聊" aria-label="Permalink to &quot;私聊&quot;">​</a></h3><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/msg &lt;玩家ID&gt; &lt;你想说的话&gt;</span></span></code></pre></div><p>或者</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/tell &lt;玩家ID&gt; &lt;你想说的话&gt;</span></span></code></pre></div><h3 id="邮件" tabindex="-1">邮件 <a class="header-anchor" href="#邮件" aria-label="Permalink to &quot;邮件&quot;">​</a></h3><p>读邮件</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mail read</span></span></code></pre></div><h3 id="系统交易" tabindex="-1">系统交易 <a class="header-anchor" href="#系统交易" aria-label="Permalink to &quot;系统交易&quot;">​</a></h3><p>卖掉手上的物品</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sell hand [数量]</span></span></code></pre></div><p>卖掉特定的物品</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sell &lt;物品ID&gt; [数量]</span></span></code></pre></div><p>卖掉物品栏中的方块</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sell blocks [数量]</span></span></code></pre></div><p>卖掉所有能卖的物品</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sell all</span></span></code></pre></div><p><a href="./item-value/">在此查看</a>服务器物品价格参照表</p><h3 id="全球市场" tabindex="-1">全球市场 <a class="header-anchor" href="#全球市场" aria-label="Permalink to &quot;全球市场&quot;">​</a></h3><p>打开市场列表：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ca gui</span></span></code></pre></div><p>发起拍卖：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ca bid &lt;价格&gt; [数量]</span></span></code></pre></div><p>出售：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ca sell &lt;价格&gt; [数量]</span></span></code></pre></div><p>收购：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ca buy &lt;价格&gt; [数量]</span></span></code></pre></div><p>打开市场邮箱</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/ca mail</span></span></code></pre></div><h3 id="转账" tabindex="-1">转账 <a class="header-anchor" href="#转账" aria-label="Permalink to &quot;转账&quot;">​</a></h3><p>向某位玩家付款：</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/pay &lt;玩家ID&gt; &lt;金额（0.01~3.4e+38）&gt;</span></span></code></pre></div><p>切换付款二次确认</p><div class="language-plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/payconfirm</span></span>
<span class="line"><span>/payconfirmon  # 开启</span></span>
<span class="line"><span>/payconfirmoff  # 关闭</span></span>
<span class="line"><span>/payconfirmtoggle</span></span></code></pre></div><details class="details custom-block"><summary>如果您不再接受付款...</summary><p>请执行<code>/paytoggle</code></p></details><h2 id="粘液科技" tabindex="-1">粘液科技 <a class="header-anchor" href="#粘液科技" aria-label="Permalink to &quot;粘液科技&quot;">​</a></h2><h3 id="获得指南" tabindex="-1">获得指南 <a class="header-anchor" href="#获得指南" aria-label="Permalink to &quot;获得指南&quot;">​</a></h3><p>获取粘液科技指南: <code>/sf guide</code></p><p>阅读粘液科技指南(但不获取书): <code>/sf open_guide</code></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>了解更多关于粘液科技的教程，请参考<a href="./slimefun/">粘液科技简易教程</a></p></div><h2 id="社交礼仪" tabindex="-1">社交礼仪 <a class="header-anchor" href="#社交礼仪" aria-label="Permalink to &quot;社交礼仪&quot;">​</a></h2><p>由于服务器内的玩家们来自于中国乃至世界各个地方，难免会因为各种各样的问题产生冲突</p><p>所以我们应该尽可能做到：</p><ul><li>多一份礼貌</li><li>多一份善良</li><li>尽可能不要爆粗口</li><li>做一些可能会影响其他玩家的事情时，应该先询问他人意见</li></ul><p>当然，如果您遇到了不怀好心的玩家，您也可以向管理组举报，管理组会视具体情况给出处罚</p><p>互动案例请查看<a href="./social-example/">社交礼仪典例</a></p><h2 id="圈地-保护领地" tabindex="-1">圈地/保护领地 <a class="header-anchor" href="#圈地-保护领地" aria-label="Permalink to &quot;圈地/保护领地&quot;">​</a></h2><p>请参见<a href="./protectionstones/">保护石插件简易教程</a></p><h2 id="创造世界" tabindex="-1">创造世界 <a class="header-anchor" href="#创造世界" aria-label="Permalink to &quot;创造世界&quot;">​</a></h2><p>我们还建立了两个创造世界，分别是<a href="./worlds/#方块元日记·创造世界">超平坦地皮①</a>以及<a href="./worlds/#方块元日记·创造世界">主世界地皮①</a></p><p>进入方法为：</p><p>依次找到<code>菜单</code>-&gt;<code>传送</code>-&gt;<code>功能性世界</code>-&gt;<code>超平坦地皮①</code>/<code>主世界地皮①</code>，并点击后即可进入</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果你想在这些世界中创作的作品受到保护，请进行<a href="#圈地-保护领地">圈地</a></p></div><h2 id="扩展功能" tabindex="-1">扩展功能 <a class="header-anchor" href="#扩展功能" aria-label="Permalink to &quot;扩展功能&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>本栏目下的大部分功能都需要客户端安装对应mod以使用</p></div><h3 id="语音模组" tabindex="-1">语音模组 <a class="header-anchor" href="#语音模组" aria-label="Permalink to &quot;语音模组&quot;">​</a></h3><p>你可以通过安装语音模组来使用服内语音功能</p><h3 id="互动点歌" tabindex="-1">互动点歌 <a class="header-anchor" href="#互动点歌" aria-label="Permalink to &quot;互动点歌&quot;">​</a></h3><p>服务器内可以通过网易云与插件，实时点歌（可被服务器所有人听见）</p><p>详细教程请前往<a href="./allmusic/">点歌插件简易教程</a></p>`,133)]))}const E=s(b,[["render",u]]);export{x as __pageData,E as default};
